  if (bucket === "qa") return ".opencode/state/qa"
  if (bucket === "smoke-test") return ".opencode/state/smoke-tests"
  if (bucket === "handoff") return ".opencode/state/handoffs"
  if (bucket === "bootstrap") return ".opencode/state/bootstrap"
